import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import styled from 'styled-components';
import { 
  Search, 
  Filter, 
  Eye, 
  Edit2, 
  CheckCircle, 
  XCircle, 
  Clock, 
  Truck, 
  Package,
  Calendar,
  DollarSign,
  User,
  Phone,
  MapPin,
  RefreshCw
} from 'lucide-react';
import Button from '../components/UI/Button';
import Input from '../components/UI/Input';
import { Card, CardBody, CardTitle } from '../components/UI/Card';
import theme from '../styles/theme';

const OrdersManagementContainer = styled.div`
  min-height: calc(100vh - 140px);
  padding: ${theme.spacing.lg};
  max-width: 1400px;
  margin: 0 auto;
`;

const ManagementHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: ${theme.spacing.xl};
  flex-wrap: wrap;
  gap: ${theme.spacing.lg};
`;

const HeaderTitle = styled.div`
  flex: 1;
`;

const ManagementTitle = styled.h1`
  font-size: ${theme.typography.fontSize['3xl']};
  font-weight: ${theme.typography.fontWeight.bold};
  color: ${theme.colors.primary};
  margin-bottom: ${theme.spacing.sm};
`;

const ManagementSubtitle = styled.p`
  color: ${theme.colors.gray[600]};
  font-size: ${theme.typography.fontSize.md};
`;

const HeaderActions = styled.div`
  display: flex;
  gap: ${theme.spacing.md};
  align-items: center;
`;

const SearchFilterSection = styled.div`
  display: flex;
  gap: ${theme.spacing.lg};
  margin-bottom: ${theme.spacing.xl};
  flex-wrap: wrap;
`;

const SearchContainer = styled.div`
  flex: 1;
  min-width: 300px;
  position: relative;
`;

const SearchIcon = styled.div`
  position: absolute;
  left: ${theme.spacing.md};
  top: 50%;
  transform: translateY(-50%);
  color: ${theme.colors.gray[400]};
  pointer-events: none;
`;

const SearchInput = styled(Input)`
  padding-left: ${theme.spacing.xl};
`;

const FilterContainer = styled.div`
  display: flex;
  gap: ${theme.spacing.md};
  align-items: center;
`;

const StatusFilter = styled.select`
  padding: ${theme.spacing.md};
  border: 1px solid ${theme.colors.gray[300]};
  border-radius: ${theme.borderRadius.md};
  background-color: ${theme.colors.white};
  font-size: ${theme.typography.fontSize.md};
  min-width: 150px;

  &:focus {
    outline: none;
    border-color: ${theme.colors.primary};
    box-shadow: 0 0 0 3px rgba(26, 54, 93, 0.1);
  }
`;

const DateFilter = styled.select`
  padding: ${theme.spacing.md};
  border: 1px solid ${theme.colors.gray[300]};
  border-radius: ${theme.borderRadius.md};
  background-color: ${theme.colors.white};
  font-size: ${theme.typography.fontSize.md};
  min-width: 150px;

  &:focus {
    outline: none;
    border-color: ${theme.colors.primary};
    box-shadow: 0 0 0 3px rgba(26, 54, 93, 0.1);
  }
`;

const OrdersTable = styled(Card)`
  overflow: hidden;
`;

const TableContainer = styled.div`
  overflow-x: auto;
`;

const Table = styled.table`
  width: 100%;
  border-collapse: collapse;
`;

const TableHeader = styled.thead`
  background-color: ${theme.colors.gray[50]};
`;

const TableRow = styled.tr`
  &:nth-child(even) {
    background-color: ${theme.colors.gray[50]};
  }

  &:hover {
    background-color: ${theme.colors.gray[100]};
  }
`;

const TableCell = styled.td`
  padding: ${theme.spacing.md};
  text-align: left;
  border-bottom: 1px solid ${theme.colors.gray[200]};
  font-size: ${theme.typography.fontSize.sm};
`;

const TableHeaderCell = styled.th`
  padding: ${theme.spacing.md};
  text-align: left;
  font-weight: ${theme.typography.fontWeight.semibold};
  color: ${theme.colors.gray[700]};
  border-bottom: 2px solid ${theme.colors.gray[200]};
  font-size: ${theme.typography.fontSize.sm};
`;

const OrderNumber = styled(Link)`
  font-weight: ${theme.typography.fontWeight.semibold};
  color: ${theme.colors.primary};
  text-decoration: none;

  &:hover {
    text-decoration: underline;
  }
`;

const CustomerInfo = styled.div`
  display: flex;
  flex-direction: column;
  gap: ${theme.spacing.xs};
`;

const CustomerName = styled.div`
  font-weight: ${theme.typography.fontWeight.medium};
`;

const CustomerContact = styled.div`
  font-size: ${theme.typography.fontSize.xs};
  color: ${theme.colors.gray[600]};
`;

const OrderStatus = styled.div.withConfig({
  shouldForwardProp: (prop) => !['status'].includes(prop)
})`
  display: flex;
  align-items: center;
  gap: ${theme.spacing.xs};
  padding: ${theme.spacing.xs} ${theme.spacing.sm};
  border-radius: ${theme.borderRadius.sm};
  font-size: ${theme.typography.fontSize.sm};
  font-weight: ${theme.typography.fontWeight.medium};
  white-space: nowrap;

  ${props => {
    switch (props.status) {
      case 'pending':
        return `
          background-color: ${theme.colors.warning}20;
          color: ${theme.colors.warning};
        `;
      case 'confirmed':
        return `
          background-color: ${theme.colors.info}20;
          color: ${theme.colors.info};
        `;
      case 'preparing':
        return `
          background-color: ${theme.colors.primary}20;
          color: ${theme.colors.primary};
        `;
      case 'ready':
        return `
          background-color: ${theme.colors.success}20;
          color: ${theme.colors.success};
        `;
      case 'delivering':
        return `
          background-color: ${theme.colors.primaryLight}20;
          color: ${theme.colors.primaryLight};
        `;
      case 'delivered':
        return `
          background-color: ${theme.colors.success}20;
          color: ${theme.colors.success};
        `;
      case 'cancelled':
        return `
          background-color: ${theme.colors.error}20;
          color: ${theme.colors.error};
        `;
      default:
        return `
          background-color: ${theme.colors.gray[500]}20;
          color: ${theme.colors.gray[500]};
        `;
    }
  }}
`;

const OrderAmount = styled.div`
  font-weight: ${theme.typography.fontWeight.semibold};
  color: ${theme.colors.primary};
`;

const OrderActions = styled.div`
  display: flex;
  gap: ${theme.spacing.xs};
`;

const ActionButton = styled(Button)`
  padding: ${theme.spacing.xs} ${theme.spacing.sm};
  font-size: ${theme.typography.fontSize.xs};
`;

const StatusModal = styled.div`
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
`;

const ModalContent = styled(Card)`
  max-width: 500px;
  width: 90%;
`;

const ModalHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: ${theme.spacing.lg};
  padding-bottom: ${theme.spacing.md};
  border-bottom: 1px solid ${theme.colors.gray[200]};
`;

const ModalTitle = styled.h2`
  font-size: ${theme.typography.fontSize['2xl']};
  font-weight: ${theme.typography.fontWeight.bold};
  color: ${theme.colors.primary};
  margin: 0;
`;

const CloseButton = styled.button`
  background: none;
  border: none;
  font-size: ${theme.typography.fontSize['2xl']};
  color: ${theme.colors.gray[500]};
  cursor: pointer;
  padding: ${theme.spacing.xs};

  &:hover {
    color: ${theme.colors.gray[700]};
  }
`;

const StatusOptions = styled.div`
  display: grid;
  gap: ${theme.spacing.md};
`;

const StatusOption = styled.label.withConfig({
  shouldForwardProp: (prop) => !['selected'].includes(prop)
})`
  display: flex;
  align-items: center;
  gap: ${theme.spacing.md};
  padding: ${theme.spacing.md};
  border: 2px solid ${props => props.selected ? theme.colors.primary : theme.colors.gray[300]};
  border-radius: ${theme.borderRadius.md};
  cursor: pointer;
  transition: all ${theme.transitions.fast};

  &:hover {
    border-color: ${theme.colors.primary};
  }
`;

const RadioInput = styled.input`
  display: none;
`;

const StatusInfo = styled.div`
  flex: 1;
`;

const StatusTitle = styled.div`
  font-weight: ${theme.typography.fontWeight.semibold};
  margin-bottom: ${theme.spacing.xs};
`;

const StatusDescription = styled.div`
  font-size: ${theme.typography.fontSize.sm};
  color: ${theme.colors.gray[600]};
`;

const LoadingMessage = styled.div`
  text-align: center;
  padding: ${theme.spacing.xl};
  color: ${theme.colors.gray[600]};
  font-size: ${theme.typography.fontSize.lg};
`;

const EmptyMessage = styled.div`
  text-align: center;
  padding: ${theme.spacing.xl};
  color: ${theme.colors.gray[600]};
  font-size: ${theme.typography.fontSize.lg};
`;

const AdminOrdersManagement = () => {
  const [orders, setOrders] = useState([]);
  const [filteredOrders, setFilteredOrders] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedStatus, setSelectedStatus] = useState('all');
  const [selectedDate, setSelectedDate] = useState('all');
  const [loading, setLoading] = useState(true);
  const [showStatusModal, setShowStatusModal] = useState(false);
  const [selectedOrder, setSelectedOrder] = useState(null);
  const [newStatus, setNewStatus] = useState('');

  const statuses = [
    { value: 'all', label: 'All Status' },
    { value: 'pending', label: 'Pending' },
    { value: 'confirmed', label: 'Confirmed' },
    { value: 'preparing', label: 'Preparing' },
    { value: 'ready', label: 'Ready' },
    { value: 'delivering', label: 'Delivering' },
    { value: 'delivered', label: 'Delivered' },
    { value: 'cancelled', label: 'Cancelled' }
  ];

  const dateFilters = [
    { value: 'all', label: 'All Time' },
    { value: 'today', label: 'Today' },
    { value: 'yesterday', label: 'Yesterday' },
    { value: 'week', label: 'This Week' },
    { value: 'month', label: 'This Month' }
  ];

  const statusOptions = [
    { value: 'pending', label: 'Pending', description: 'Order received, awaiting confirmation' },
    { value: 'confirmed', label: 'Confirmed', description: 'Order confirmed and being prepared' },
    { value: 'preparing', label: 'Preparing', description: 'Food is being prepared' },
    { value: 'ready', label: 'Ready', description: 'Food is ready for pickup/delivery' },
    { value: 'delivering', label: 'Delivering', description: 'Order is out for delivery' },
    { value: 'delivered', label: 'Delivered', description: 'Order has been delivered' },
    { value: 'cancelled', label: 'Cancelled', description: 'Order was cancelled' }
  ];

  const statusIcons = {
    pending: Clock,
    confirmed: CheckCircle,
    preparing: Clock,
    ready: CheckCircle,
    delivering: Truck,
    delivered: CheckCircle,
    cancelled: XCircle
  };

  useEffect(() => {
    // Mock data - in real app, this would come from API
    const mockOrders = [
      {
        id: 1,
        orderNumber: 'ORD-001',
        customer: {
          name: 'John Doe',
          phone: '+1 (555) 123-4567',
          email: 'john.doe@example.com'
        },
        status: 'pending',
        amount: 45.99,
        date: new Date(),
        items: ['Classic Burger', 'French Fries', 'Coca Cola'],
        address: '123 Main Street, New York, NY 10001'
      },
      {
        id: 2,
        orderNumber: 'ORD-002',
        customer: {
          name: 'Jane Smith',
          phone: '+1 (555) 987-6543',
          email: 'jane.smith@example.com'
        },
        status: 'confirmed',
        amount: 32.50,
        date: new Date(Date.now() - 3600000),
        items: ['Margherita Pizza', 'Garlic Bread'],
        address: '456 Oak Avenue, Brooklyn, NY 11201'
      },
      {
        id: 3,
        orderNumber: 'ORD-003',
        customer: {
          name: 'Bob Johnson',
          phone: '+1 (555) 456-7890',
          email: 'bob.johnson@example.com'
        },
        status: 'preparing',
        amount: 67.25,
        date: new Date(Date.now() - 7200000),
        items: ['Caesar Salad', 'Grilled Chicken', 'Fresh Juice'],
        address: '789 Elm Street, Queens, NY 11375'
      },
      {
        id: 4,
        orderNumber: 'ORD-004',
        customer: {
          name: 'Alice Brown',
          phone: '+1 (555) 234-5678',
          email: 'alice.brown@example.com'
        },
        status: 'delivering',
        amount: 28.75,
        date: new Date(Date.now() - 10800000),
        items: ['Chicken Wings', 'Onion Rings'],
        address: '321 Pine Road, Manhattan, NY 10002'
      },
      {
        id: 5,
        orderNumber: 'ORD-005',
        customer: {
          name: 'Charlie Wilson',
          phone: '+1 (555) 345-6789',
          email: 'charlie.wilson@example.com'
        },
        status: 'delivered',
        amount: 51.00,
        date: new Date(Date.now() - 86400000),
        items: ['Veggie Pizza', 'Garden Salad'],
        address: '654 Maple Drive, Bronx, NY 10451'
      }
    ];

    setTimeout(() => {
      setOrders(mockOrders);
      setFilteredOrders(mockOrders);
      setLoading(false);
    }, 1000);
  }, []);

  useEffect(() => {
    let filtered = orders;

    if (searchTerm) {
      filtered = filtered.filter(order =>
        order.orderNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        order.customer.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        order.customer.email.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedStatus !== 'all') {
      filtered = filtered.filter(order => order.status === selectedStatus);
    }

    // Apply date filter
    if (selectedDate !== 'all') {
      const now = new Date();
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

      filtered = filtered.filter(order => {
        const orderDate = new Date(order.date);

        switch (selectedDate) {
          case 'today':
            return orderDate >= today;
          case 'yesterday':
            const yesterday = new Date(today);
            yesterday.setDate(yesterday.getDate() - 1);
            return orderDate >= yesterday && orderDate < today;
          case 'week':
            const weekAgo = new Date(today);
            weekAgo.setDate(weekAgo.getDate() - 7);
            return orderDate >= weekAgo;
          case 'month':
            const monthAgo = new Date(today);
            monthAgo.setMonth(monthAgo.getMonth() - 1);
            return orderDate >= monthAgo;
          default:
            return true;
        }
      });
    }

    setFilteredOrders(filtered);
  }, [searchTerm, selectedStatus, selectedDate, orders]);

  const handleStatusUpdate = (order) => {
    setSelectedOrder(order);
    setNewStatus(order.status);
    setShowStatusModal(true);
  };

  const handleStatusChange = (status) => {
    setNewStatus(status);
  };

  const handleSaveStatus = () => {
    if (selectedOrder && newStatus) {
      setOrders(prev => prev.map(order => 
        order.id === selectedOrder.id 
          ? { ...order, status: newStatus }
          : order
      ));
      setShowStatusModal(false);
      setSelectedOrder(null);
      setNewStatus('');
    }
  };

  const formatDate = (date) => {
    return new Intl.DateTimeFormat('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    }).format(date);
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD'
    }).format(amount);
  };

  if (loading) {
    return (
      <OrdersManagementContainer>
        <LoadingMessage>Loading orders...</LoadingMessage>
      </OrdersManagementContainer>
    );
  }

  return (
    <OrdersManagementContainer>
      <ManagementHeader>
        <HeaderTitle>
          <ManagementTitle>Orders Management</ManagementTitle>
          <ManagementSubtitle>Manage and track all customer orders</ManagementSubtitle>
        </HeaderTitle>
        <HeaderActions>
          <Button onClick={() => window.location.reload()}>
            <RefreshCw size={20} />
            Refresh
          </Button>
        </HeaderActions>
      </ManagementHeader>

      <SearchFilterSection>
        <SearchContainer>
          <SearchIcon>
            <Search size={20} />
          </SearchIcon>
          <SearchInput
            type="text"
            placeholder="Search by order number, customer name, or email..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </SearchContainer>

        <FilterContainer>
          <Filter size={20} style={{ color: theme.colors.gray[500] }} />
          <StatusFilter
            value={selectedStatus}
            onChange={(e) => setSelectedStatus(e.target.value)}
          >
            {statuses.map(status => (
              <option key={status.value} value={status.value}>
                {status.label}
              </option>
            ))}
          </StatusFilter>

          <DateFilter
            value={selectedDate}
            onChange={(e) => setSelectedDate(e.target.value)}
          >
            {dateFilters.map(filter => (
              <option key={filter.value} value={filter.value}>
                {filter.label}
              </option>
            ))}
          </DateFilter>
        </FilterContainer>
      </SearchFilterSection>

      <OrdersTable>
        <CardBody style={{ padding: 0 }}>
          <TableContainer>
            <Table>
              <TableHeader>
                <tr>
                  <TableHeaderCell>Order #</TableHeaderCell>
                  <TableHeaderCell>Customer</TableHeaderCell>
                  <TableHeaderCell>Status</TableHeaderCell>
                  <TableHeaderCell>Amount</TableHeaderCell>
                  <TableHeaderCell>Date</TableHeaderCell>
                  <TableHeaderCell>Actions</TableHeaderCell>
                </tr>
              </TableHeader>
              <tbody>
                {filteredOrders.map(order => {
                  const StatusIcon = statusIcons[order.status] || Clock;
                  return (
                    <TableRow key={order.id}>
                      <TableCell>
                        <OrderNumber to={`/orders/${order.id}`}>
                          {order.orderNumber}
                        </OrderNumber>
                      </TableCell>
                      <TableCell>
                        <CustomerInfo>
                          <CustomerName>{order.customer.name}</CustomerName>
                          <CustomerContact>{order.customer.email}</CustomerContact>
                          <CustomerContact>{order.customer.phone}</CustomerContact>
                        </CustomerInfo>
                      </TableCell>
                      <TableCell>
                        <OrderStatus status={order.status}>
                          <StatusIcon size={14} />
                          {order.status.charAt(0).toUpperCase() + order.status.slice(1)}
                        </OrderStatus>
                      </TableCell>
                      <TableCell>
                        <OrderAmount>{formatCurrency(order.amount)}</OrderAmount>
                      </TableCell>
                      <TableCell>
                        {formatDate(order.date)}
                      </TableCell>
                      <TableCell>
                        <OrderActions>
                          <ActionButton variant="outline" as={Link} to={`/orders/${order.id}`}>
                            <Eye size={14} />
                          </ActionButton>
                          <ActionButton 
                            variant="outline" 
                            onClick={() => handleStatusUpdate(order)}
                          >
                            <Edit2 size={14} />
                          </ActionButton>
                        </OrderActions>
                      </TableCell>
                    </TableRow>
                  );
                })}
              </tbody>
            </Table>
          </TableContainer>
        </CardBody>
      </OrdersTable>

      {filteredOrders.length === 0 && (
        <EmptyMessage>
          No orders found matching your criteria.
        </EmptyMessage>
      )}

      {showStatusModal && selectedOrder && (
        <StatusModal>
          <ModalContent>
            <CardBody>
              <ModalHeader>
                <ModalTitle>Update Order Status</ModalTitle>
                <CloseButton onClick={() => setShowStatusModal(false)}>
                  ×
                </CloseButton>
              </ModalHeader>

              <div style={{ marginBottom: theme.spacing.lg }}>
                <p><strong>Order:</strong> {selectedOrder.orderNumber}</p>
                <p><strong>Customer:</strong> {selectedOrder.customer.name}</p>
                <p><strong>Current Status:</strong> {selectedOrder.status.charAt(0).toUpperCase() + selectedOrder.status.slice(1)}</p>
              </div>

              <StatusOptions>
                {statusOptions.map(option => {
                  const OptionIcon = statusIcons[option.value] || Clock;
                  return (
                    <StatusOption
                      key={option.value}
                      selected={newStatus === option.value}
                      onClick={() => handleStatusChange(option.value)}
                    >
                      <RadioInput
                        type="radio"
                        name="status"
                        value={option.value}
                        checked={newStatus === option.value}
                        onChange={() => handleStatusChange(option.value)}
                      />
                      <OptionIcon size={20} />
                      <StatusInfo>
                        <StatusTitle>{option.label}</StatusTitle>
                        <StatusDescription>{option.description}</StatusDescription>
                      </StatusInfo>
                    </StatusOption>
                  );
                })}
              </StatusOptions>

              <div style={{ display: 'flex', gap: theme.spacing.md, marginTop: theme.spacing.xl }}>
                <Button onClick={handleSaveStatus}>
                  Update Status
                </Button>
                <Button 
                  variant="outline" 
                  onClick={() => setShowStatusModal(false)}
                >
                  Cancel
                </Button>
              </div>
            </CardBody>
          </ModalContent>
        </StatusModal>
      )}
    </OrdersManagementContainer>
  );
};

export default AdminOrdersManagement;
